{%- set CAT = ["TG","TE","SE","OA","FD","GP","OT"] -%}
{%- set CAT_FULL = {"TG":["Transport","Goods"],"TE":["Transport","Employee"],"SE":["Spares /","Engineering"],"OA":["Office /","Admin"],"FD":["Food",""],"GP":["Geeprint",""],"OT":["Other",""]} -%}
{%- set VEHICLES = ["KAP 466","KAY 635","KCB 430","KBQ 788","KBT 972"] -%}
{%- set DAYS = ["Mon","Tue","Wed","Thu","Fri","Sat"] -%}
{%- set DAY_FULL = {"Mon":"Monday","Tue":"Tuesday","Wed":"Wednesday","Thu":"Thursday","Fri":"Friday","Sat":"Saturday"} -%}

{# -------- Voucher totals (inline filters, scalar namespace only — NO dict mutation) -------- #}
{%- set s = namespace(cat_in=0, voucher_out=0, pc=0, etr=0, used=0) -%}
{%- set s.cat_in = doc.vouchers | selectattr("cash_in") | sum(attribute="amount") -%}
{%- set s.voucher_out = doc.vouchers | rejectattr("cash_in") | sum(attribute="amount") -%}
{%- set s.pc = doc.vouchers | selectattr("pc_received") | list | length -%}
{%- set s.etr = doc.vouchers | selectattr("etr_received") | list | length -%}
{%- for v in doc.vouchers -%}
  {%- if v.voucher_no or v.recipient or (v.amount or 0) %}{% set s.used = s.used + 1 %}{% endif -%}
{%- endfor -%}

{# -------- Receipt-coverage matrix (spend rows only, no dict mutation) -------- #}
{%- set rc = namespace(doc_n=0, doc_a=0, pc_n=0, pc_a=0, etr_n=0, etr_a=0, both_n=0, both_a=0, none_n=0, none_a=0) -%}
{%- for v in doc.vouchers -%}
  {%- if not v.cash_in and (v.amount or 0) > 0 -%}
    {%- set _amt = v.amount or 0 -%}
    {%- if v.pc_received and v.etr_received -%}
      {%- set rc.both_n = rc.both_n + 1 %}{% set rc.both_a = rc.both_a + _amt %}{% set rc.doc_n = rc.doc_n + 1 %}{% set rc.doc_a = rc.doc_a + _amt -%}
    {%- elif v.pc_received -%}
      {%- set rc.pc_n = rc.pc_n + 1 %}{% set rc.pc_a = rc.pc_a + _amt %}{% set rc.doc_n = rc.doc_n + 1 %}{% set rc.doc_a = rc.doc_a + _amt -%}
    {%- elif v.etr_received -%}
      {%- set rc.etr_n = rc.etr_n + 1 %}{% set rc.etr_a = rc.etr_a + _amt %}{% set rc.doc_n = rc.doc_n + 1 %}{% set rc.doc_a = rc.doc_a + _amt -%}
    {%- else -%}
      {%- set rc.none_n = rc.none_n + 1 %}{% set rc.none_a = rc.none_a + _amt -%}
    {%- endif -%}
  {%- endif -%}
{%- endfor -%}

{# -------- Parking totals -------- #}
{%- set pk = namespace(total=0) -%}
{%- set pk.total = doc.parking_entries | sum(attribute="amount") -%}

{# -------- Bike / Forklift -------- #}
{%- set mz = namespace(bike=0, fork=0) -%}
{%- set mz.bike = doc.misc_entries | selectattr("kind","equalto","Bike Fuel") | sum(attribute="amount") -%}
{%- set mz.fork = doc.misc_entries | selectattr("kind","equalto","Forklift") | sum(attribute="amount") -%}
{%- set bike_rows = (doc.misc_entries | selectattr("kind","equalto","Bike Fuel") | list) -%}
{%- set fork_rows = (doc.misc_entries | selectattr("kind","equalto","Forklift") | list) -%}

{# -------- Wages / Loans -------- #}
{%- set wl = namespace(wages=0, loans=0, signed=0) -%}
{%- set wl.wages = doc.wages_entries | sum(attribute="amount") -%}
{%- set wl.loans = doc.loan_entries | sum(attribute="amount_issued") -%}
{%- set wl.signed = doc.loan_entries | sum(attribute="amount_signed") -%}

{# -------- Week dates (Mon..Sat ending on the Friday) -------- #}
{%- set monday = frappe.utils.add_days(doc.week_ending, -4) if doc.week_ending else None -%}

{# -------- Cross-sheet LOAN LEDGER: every loan up to & including this sheet's week_ending.
   Guarded so the offline mock render (no frappe) still succeeds. -------- #}
{%- set ledger = namespace(rows=[], issued=0, signed=0, ok=False) -%}
{%- if frappe is defined and frappe.get_all is defined and doc.week_ending -%}
  {%- set _try = namespace(rows=None) -%}
  {%- set _try.rows = frappe.get_all("Petty Cash Loan Entry",
        filters={"parenttype": "Petty Cash Sheet"},
        fields=["parent","txn_date","recipient","staff_id","reason","amount_issued","amount_signed","paye"],
        order_by="txn_date asc, idx asc", limit_page_length=0, ignore_permissions=True) -%}
  {%- if _try.rows is not none -%}
    {%- set _parents = _try.rows | map(attribute="parent") | list -%}
    {%- set _sheets = frappe.get_all("Petty Cash Sheet",
          filters={"name": ["in", _parents]},
          fields=["name","week_ending","float"], limit_page_length=0, ignore_permissions=True) if _parents else [] -%}
    {%- for r in _try.rows -%}
      {%- set _sh = (_sheets | selectattr("name","equalto", r.parent) | list | first) if _sheets else None -%}
      {%- set _we = _sh.week_ending if _sh else None -%}
      {%- set _fl = _sh.float if _sh else "" -%}
      {%- if _we and _we <= doc.week_ending -%}
        {%- set _cur = (_sh.name == doc.name) -%}
        {%- set ledger.rows = ledger.rows + [{"week_ending": _we, "float": _fl, "txn_date": r.txn_date,
              "recipient": r.recipient, "staff_id": r.staff_id, "reason": r.reason,
              "amount_issued": r.amount_issued or 0, "amount_signed": r.amount_signed or 0,
              "paye": r.paye, "is_current": _cur}] -%}
        {%- set ledger.issued = ledger.issued + (r.amount_issued or 0) -%}
        {%- set ledger.signed = ledger.signed + (r.amount_signed or 0) -%}
        {%- set ledger.ok = True -%}
      {%- endif -%}
    {%- endfor -%}
  {%- endif -%}
{%- endif -%}

<div class="pcws">
<style>
  .pcws { font-family: Arial, Helvetica, sans-serif; color:#000; font-size:11px; }
  .pcws .title-bar { background:#1D2766; color:#fff; padding:8px 14px; font-weight:bold; font-size:14px; border:2px solid #14182b; display:flex; justify-content:space-between; align-items:center; }
  .pcws .title-bar .sub { font-size:12px; font-weight:normal; opacity:0.95; }
  .pcws table { width:100%; border-collapse:collapse; margin-top:4px; font-size:11px; table-layout:fixed; }
  .pcws th, .pcws td { border:1px solid #000; padding:4px 6px; vertical-align:middle; word-wrap:break-word; }
  .pcws th { background:#1D2766; color:#fff; font-weight:bold; text-align:center; font-size:10px; line-height:1.15; }
  .pcws td.right, .pcws th.right { text-align:right; }
  .pcws td.center, .pcws th.center { text-align:center; }
  .pcws td.lbl { background:#F5F6FA; font-weight:bold; text-align:left; }
  .pcws th.lbl { background:#F5F6FA; color:#1D2766; text-align:left; }
  .pcws .cat-cell { background:#EEF1FA; }
  .pcws .in-cell { background:#E8F5E9; }
  .pcws tr.totals td { background:#E8EAF0; font-weight:bold; }
  .pcws tr.totals td.cat-cell { background:#EEF1FA; }
  .pcws tr.totals td.in-cell { background:#E8F5E9; }
  .pcws .hi { background:#FFF8E1; font-weight:bold; }
  .pcws th.hi { background:#B86B00; color:#fff; }
  .pcws td.hi-amber { background:#FFF0CC; font-weight:bold; }
  .pcws .section-h { background:#1D2766; color:#fff; font-weight:bold; padding:5px 12px; font-size:12px; border:1px solid #000; margin-top:10px; }
  .pcws .code-legend { background:#F5F6FA; padding:6px 12px; font-size:10px; border:1px solid #CBD2E0; margin-top:4px; }
  .pcws .code-legend .code { font-weight:bold; color:#2B3990; }
  .pcws .code-legend .red-code { font-weight:bold; color:#C00000; }
  .pcws .code-legend .sep { color:#BBB; margin:0 6px; }
  .pcws .code-legend .chip { display:inline-block; width:11px; height:11px; background:#FFF0CC; border:1px solid #B86B00; vertical-align:-1px; margin:0 3px; }
  .pcws .recon-two { display:flex; gap:12px; margin-top:4px; }
  .pcws .recon-two > div { flex:1; }
  .pcws .recon-two h3 { margin:4px 0; color:#1D2766; font-size:12px; }
  .pcws tr.missing td { background:#FFF0CC; }
  .pcws tr.missing td.cat-cell { background:#FFE8B0; }
  .pcws tr.missing td:first-child { box-shadow: inset 4px 0 0 #B86B00; }
  .pcws .note { margin-top:8px; font-size:10px; color:#333; }
  .pcws .note .red { color:#C00000; font-weight:bold; }
  .pcws .page-break { page-break-before: always; }
  @media print {
    .pcws table { page-break-inside:auto; }
    .pcws thead { display:table-header-group; }
    .pcws tfoot { display:table-row-group; }
    .pcws tr { page-break-inside:avoid; }
    @page { size: A4 portrait; margin: 8mm; }
  }
</style>

{# ============================================================
   PAGE 1 — RECONCILIATION & SUMMARY COVER
   ============================================================ #}
<div class="title-bar">
  <div>VIMIT CONVERTERS LIMITED &nbsp;|&nbsp; <span class="sub">WEEKLY PETTY CASH &mdash; RECONCILIATION &amp; SUMMARY</span></div>
  <div class="sub">COVER &middot; Wk {{ doc.week_no }} &middot; {{ doc.float }} Float</div>
</div>

<table>
  <colgroup><col style="width:12%"><col style="width:24%"><col style="width:34%"><col style="width:30%"></colgroup>
  <tr><th>WEEK NO</th><th>WEEK ENDING</th><th>CUSTODIAN</th><th>OPENING BALANCE (KES)</th></tr>
  <tr>
    <td class="center">{{ doc.week_no }}</td>
    <td>{{ frappe.utils.format_date(doc.week_ending) if doc.week_ending else "" }}</td>
    <td>{{ doc.custodian_name or doc.custodian or "" }}</td>
    <td class="right">{{ "{:,.0f}".format(doc.opening_balance or 0) }}</td>
  </tr>
</table>

<div class="section-h">CATEGORY BREAKDOWN (from Voucher Register)</div>
<table>
  <colgroup><col style="width:18%"><col style="width:10%"><col style="width:10%"><col style="width:10%"><col style="width:10%"><col style="width:9%"><col style="width:9%"><col style="width:9%"><col style="width:15%"></colgroup>
  <thead>
    <tr>
      <th class="lbl">VOUCHER REGISTER &mdash; BY CATEGORY</th>
      {% for c in CAT %}<th>{{ CAT_FULL[c][0] }}{% if CAT_FULL[c][1] %}<br>{{ CAT_FULL[c][1] }}{% endif %}</th>{% endfor %}
      <th>TOTAL</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td class="lbl">Cash OUT (KES)</td>
      {% for c in CAT %}{% set catout = doc.vouchers | rejectattr("cash_in") | selectattr("category","equalto",c) | sum(attribute="amount") %}<td class="right">{{ "{:,.0f}".format(catout) if catout else "" }}</td>{% endfor %}
      <td class="right hi">{{ "{:,.0f}".format(s.voucher_out) if s.voucher_out else "" }}</td>
    </tr>
    <tr>
      <td class="lbl">Cash IN (KES) &mdash; refunds</td>
      <td colspan="7" style="background:#F5F6FA"></td>
      <td class="right hi">{{ "{:,.0f}".format(s.cat_in) if s.cat_in else "" }}</td>
    </tr>
    <tr>
      <td class="lbl">Vouchers / Receipts</td>
      <td colspan="7" style="text-align:right">PC slips: <strong>{{ s.pc }}</strong> &middot; ETR receipts: <strong>{{ s.etr }}</strong> &middot; rows used: <strong>{{ s.used }}</strong></td>
      <td></td>
    </tr>
    <tr>
      <td class="lbl">% of Voucher Spend</td>
      {% for c in CAT %}{% set catout = doc.vouchers | rejectattr("cash_in") | selectattr("category","equalto",c) | sum(attribute="amount") %}<td class="center" style="background:#E8EAF0;font-weight:bold">{% if s.voucher_out and s.voucher_out > 0 %}{{ ((catout / s.voucher_out) * 100)|round(0)|int }}%{% else %}&mdash;{% endif %}</td>{% endfor %}
      <td class="center" style="background:#E8EAF0;font-weight:bold;color:#1D2766">100%</td>
    </tr>
  </tbody>
</table>

<div class="section-h">VEHICLE BREAKDOWN (from Vehicle Sheet)</div>
<table>
  <colgroup><col style="width:22%"><col style="width:11%"><col style="width:11%"><col style="width:11%"><col style="width:11%"><col style="width:11%"><col style="width:11%"><col style="width:12%"></colgroup>
  <thead>
    <tr>
      <th class="lbl">VEHICLE SHEET &mdash; BY VEHICLE</th>
      {% for vh in VEHICLES %}<th>{{ vh }}</th>{% endfor %}
      <th>BIKE</th>
      <th>FORKLIFT</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td class="lbl">Weekly Spend (KES)</td>
      {% for vh in VEHICLES %}{% set vtot = doc.parking_entries | selectattr("vehicle","equalto",vh) | sum(attribute="amount") %}<td class="right">{{ "{:,.0f}".format(vtot) if vtot else "" }}</td>{% endfor %}
      <td class="right">{{ "{:,.0f}".format(mz.bike) if mz.bike else "" }}</td>
      <td class="right hi">{{ "{:,.0f}".format(mz.fork) if mz.fork else "" }}</td>
    </tr>
  </tbody>
</table>

<div class="section-h">END OF WEEK RECONCILIATION</div>
<div class="recon-two">
  <div>
    <h3>CASH MOVEMENT</h3>
    <table>
      <colgroup><col style="width:65%"><col style="width:35%"></colgroup>
      <tr><td class="lbl">A. Opening Balance (start of week)</td><td class="right">{{ "{:,.0f}".format(doc.opening_balance or 0) }}</td></tr>
      <tr><td class="lbl">B. Total Cash OUT (vouchers + vehicle + bike + forklift + wages + loans)</td><td class="right">{{ "{:,.0f}".format(doc.total_out or 0) }}</td></tr>
      <tr><td class="lbl">C. Total Cash IN (refunds)</td><td class="right">{{ "{:,.0f}".format(doc.total_in or 0) }}</td></tr>
      <tr class="totals"><td class="lbl" style="background:#FFF8E1">D. EXPECTED CLOSING = A &minus; B + C</td><td class="right hi">{{ "{:,.0f}".format(doc.expected_close or 0) }}</td></tr>
    </table>
  </div>
  <div>
    <h3>PHYSICAL RECONCILIATION</h3>
    <table>
      <colgroup><col style="width:65%"><col style="width:35%"></colgroup>
      <tr><td class="lbl">E. Physical Cash Count (end of week)</td><td class="right">{{ "{:,.0f}".format(doc.cash_count_end or 0) }}</td></tr>
      <tr><td class="lbl">F. Sum of Open Vouchers (cash out)</td><td class="right"></td></tr>
      <tr class="totals"><td class="lbl" style="background:#FFF8E1">G. AUTHORISED FLOAT</td><td class="right hi">{{ "{:,.0f}".format(doc.authorised_float or 0) }}</td></tr>
      <tr class="totals"><td class="lbl" style="background:#FFF8E1">H. VARIANCE = E &minus; D</td><td class="right hi">{{ "{:,.0f}".format(doc.variance or 0) }}</td></tr>
    </table>
  </div>
</div>

<table style="margin-top:10px">
  <colgroup><col style="width:24%"><col style="width:9%"><col style="width:24%"><col style="width:9%"><col style="width:24%"><col style="width:10%"></colgroup>
  <thead>
    <tr><th>CUSTODIAN &mdash; PREPARED</th><th>DATE</th><th>FINANCE MANAGER &mdash; REVIEWED</th><th>DATE</th><th>CFO &mdash; APPROVED</th><th>DATE</th></tr>
  </thead>
  <tbody>
    <tr><td style="height:48px"></td><td></td><td></td><td></td><td></td><td></td></tr>
  </tbody>
</table>

{# ============================================================
   PAGE 2 — VOUCHER REGISTER (receipt matrix + OUT-by-category)
   ============================================================ #}
<div class="page-break"></div>
<div class="title-bar">
  <div>VIMIT CONVERTERS LIMITED &nbsp;|&nbsp; <span class="sub">WEEKLY PETTY CASH &mdash; VOUCHER REGISTER</span></div>
  <div class="sub">Wk {{ doc.week_no }} &middot; {{ doc.float }} Float &middot; {{ frappe.utils.format_date(doc.week_ending) if doc.week_ending else "" }}</div>
</div>

<div class="section-h">RECEIPT COVERAGE (rows with spend)</div>
<table>
  <colgroup><col style="width:18%"><col style="width:15%"><col style="width:15%"><col style="width:15%"><col style="width:13%"><col style="width:24%"></colgroup>
  <thead>
    <tr>
      <th class="lbl">Receipt coverage</th>
      <th>Documented<br>PC&#10003; or ETR&#10003;</th>
      <th>PC slip only<br>most common</th>
      <th>ETR only<br>vendor-issued</th>
      <th>Both &#10003;&#10003;<br>rare</th>
      <th class="hi">No receipt at all<br>amber rows below</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td class="lbl">Rows with spend</td>
      <td class="center"><strong>{{ rc.doc_n }}</strong></td>
      <td class="center"><strong>{{ rc.pc_n }}</strong></td>
      <td class="center"><strong>{{ rc.etr_n }}</strong></td>
      <td class="center"><strong>{{ rc.both_n }}</strong></td>
      <td class="center hi-amber"><strong>{{ rc.none_n }}</strong></td>
    </tr>
    <tr>
      <td class="lbl">KES amount</td>
      <td class="right">{{ "{:,.0f}".format(rc.doc_a) if rc.doc_a else "" }}</td>
      <td class="right">{{ "{:,.0f}".format(rc.pc_a) if rc.pc_a else "" }}</td>
      <td class="right">{{ "{:,.0f}".format(rc.etr_a) if rc.etr_a else "" }}</td>
      <td class="right">{{ "{:,.0f}".format(rc.both_a) if rc.both_a else "" }}</td>
      <td class="right hi-amber">{{ "{:,.0f}".format(rc.none_a) if rc.none_a else "" }}</td>
    </tr>
  </tbody>
</table>

<div class="code-legend">
  <span class="code">TG</span> Transport-Goods <span class="sep">&middot;</span>
  <span class="code">TE</span> Transport-Employee <span class="sep">&middot;</span>
  <span class="code">SE</span> Spares/Engineering <span class="sep">&middot;</span>
  <span class="code">OA</span> Office/Admin <span class="sep">&middot;</span>
  <span class="code">FD</span> Food <span class="sep">&middot;</span>
  <span class="code">GP</span> Geeprint <span class="sep">&middot;</span>
  <span class="code">OT</span> Other <span class="sep">|</span>
  <span class="red-code">PC</span> = Petty Cash slip <span class="sep">&middot;</span>
  <span class="red-code">ETR</span> = KRA ETR receipt <span class="sep">|</span>
  <span class="chip"></span> = spend with neither PC nor ETR
</div>

<table>
  <colgroup>
    <col style="width:3%"><col style="width:7%"><col style="width:8%"><col style="width:13%">
    <col style="width:5.5%"><col style="width:5.5%"><col style="width:5.5%"><col style="width:5.5%"><col style="width:5.5%"><col style="width:5.5%"><col style="width:5.5%">
    <col style="width:6%">
    <col style="width:3.5%"><col style="width:3.5%">
    <col style="width:9%"><col style="width:3%">
  </colgroup>
  <thead>
    <tr>
      <th rowspan="2">#</th><th rowspan="2">DATE</th><th rowspan="2">VOUCHER NO</th><th rowspan="2">RECIPIENT</th>
      <th colspan="7" style="background:#C00000;color:#fff">OUT (KES) &mdash; by category</th>
      <th rowspan="2" style="background:#1B5E20;color:#fff">IN<br>(KES)</th>
      <th rowspan="2">PC</th><th rowspan="2">ETR</th>
      <th rowspan="2">NOTES</th><th rowspan="2">SIGN</th>
    </tr>
    <tr>
      {% for c in CAT %}<th>{{ CAT_FULL[c][0] }}{% if CAT_FULL[c][1] %}<br>{{ CAT_FULL[c][1] }}{% endif %}</th>{% endfor %}
    </tr>
  </thead>
  <tbody>
    {% for v in doc.vouchers %}
    {% if v.voucher_no or v.recipient or v.amount or v.category %}
    {% set needs = (v.amount or 0) and not v.cash_in and not v.pc_received and not v.etr_received %}
    <tr {% if needs %}class="missing"{% endif %}>
      <td class="center">{{ v.row_idx }}</td>
      <td>{{ frappe.utils.format_date(v.txn_date) if v.txn_date else "" }}</td>
      <td>{{ v.voucher_no or "" }}</td>
      <td>{{ v.recipient or "" }}</td>
      {% for c in CAT %}<td class="cat-cell right">{% if (not v.cash_in) and v.category == c and v.amount %}{{ "{:,.0f}".format(v.amount) }}{% endif %}</td>{% endfor %}
      <td class="in-cell right">{% if v.cash_in and v.amount %}{{ "{:,.0f}".format(v.amount) }}{% endif %}</td>
      <td class="center">{% if v.pc_received %}&#10003;{% endif %}</td>
      <td class="center">{% if v.etr_received %}&#10003;{% endif %}</td>
      <td>{{ v.notes or "" }}</td>
      <td></td>
    </tr>
    {% endif %}
    {% endfor %}
    <tr class="totals">
      <td colspan="4" class="right">WEEKLY TOTALS &rarr;</td>
      {% for c in CAT %}{% set catout = doc.vouchers | rejectattr("cash_in") | selectattr("category","equalto",c) | sum(attribute="amount") %}<td class="cat-cell right">{{ "{:,.0f}".format(catout) if catout else "" }}</td>{% endfor %}
      <td class="in-cell right">{{ "{:,.0f}".format(s.cat_in) if s.cat_in else "" }}</td>
      <td colspan="4"></td>
    </tr>
  </tbody>
</table>

{# ============================================================
   PAGE 3 — VEHICLE EXPENSES
   ============================================================ #}
<div class="page-break"></div>
<div class="title-bar">
  <div>VIMIT CONVERTERS LIMITED &nbsp;|&nbsp; <span class="sub">WEEKLY PETTY CASH &mdash; VEHICLE EXPENSES</span></div>
  <div class="sub">Wk {{ doc.week_no }} &middot; {{ doc.float }} Float &middot; {{ frappe.utils.format_date(doc.week_ending) if doc.week_ending else "" }}</div>
</div>

<div class="section-h">SECTION A &mdash; VEHICLE PARKING (KES)</div>
<table>
  <colgroup><col style="width:11%"><col style="width:13%"><col style="width:13%"><col style="width:13%"><col style="width:13%"><col style="width:13%"><col style="width:13%"><col style="width:11%"></colgroup>
  <thead>
    <tr><th>DAY</th><th>DATE</th>{% for vh in VEHICLES %}<th>{{ vh }}</th>{% endfor %}<th>DAILY TOTAL</th></tr>
  </thead>
  <tbody>
    {% for di in range(6) %}
    {% set dn = DAYS[di] %}
    {% set ddate = frappe.utils.add_days(monday, di) if monday else None %}
    <tr>
      <td class="center">{{ DAY_FULL[dn] }}</td>
      <td>{{ frappe.utils.format_date(ddate) if ddate else "" }}</td>
      {% for vh in VEHICLES %}
        {% set vt = doc.parking_entries | selectattr("day_idx","equalto",dn) | selectattr("vehicle","equalto",vh) | sum(attribute="amount") %}
        <td class="right">{{ "{:,.0f}".format(vt) if vt else "" }}</td>
      {% endfor %}
      {% set dtot = doc.parking_entries | selectattr("day_idx","equalto",dn) | sum(attribute="amount") %}<td class="right">{{ "{:,.0f}".format(dtot) if dtot else "" }}</td>
    </tr>
    {% endfor %}
    <tr class="totals">
      <td colspan="2" class="right">WEEKLY TOTAL</td>
      {% for vh in VEHICLES %}{% set vtot = doc.parking_entries | selectattr("vehicle","equalto",vh) | sum(attribute="amount") %}<td class="right">{{ "{:,.0f}".format(vtot) if vtot else "" }}</td>{% endfor %}
      <td class="right">{{ "{:,.0f}".format(pk.total) if pk.total else "" }}</td>
    </tr>
  </tbody>
</table>

<div class="section-h">SECTION B &mdash; BIKE FUEL &amp; FORKLIFT (KES)</div>
<table>
  <colgroup><col style="width:8%"><col style="width:13%"><col style="width:16%"><col style="width:13%"><col style="width:8%"><col style="width:13%"><col style="width:16%"><col style="width:13%"></colgroup>
  <thead>
    <tr>
      <th colspan="4">BIKE FUEL</th>
      <th colspan="4">FORKLIFT</th>
    </tr>
    <tr>
      <th>#</th><th>DATE</th><th>AMOUNT</th><th>SIGN</th>
      <th>#</th><th>DATE</th><th>AMOUNT</th><th>SIGN</th>
    </tr>
  </thead>
  <tbody>
    {% set bf_max = [bike_rows|length, fork_rows|length]|max %}
    {% for i in range(bf_max) %}
    <tr>
      <td class="center">{% if i < bike_rows|length %}{{ bike_rows[i].row_idx }}{% endif %}</td>
      <td>{% if i < bike_rows|length and bike_rows[i].txn_date %}{{ frappe.utils.format_date(bike_rows[i].txn_date) }}{% endif %}</td>
      <td class="right">{% if i < bike_rows|length and bike_rows[i].amount %}{{ "{:,.0f}".format(bike_rows[i].amount) }}{% endif %}</td>
      <td></td>
      <td class="center">{% if i < fork_rows|length %}{{ fork_rows[i].row_idx }}{% endif %}</td>
      <td>{% if i < fork_rows|length and fork_rows[i].txn_date %}{{ frappe.utils.format_date(fork_rows[i].txn_date) }}{% endif %}</td>
      <td class="right">{% if i < fork_rows|length and fork_rows[i].amount %}{{ "{:,.0f}".format(fork_rows[i].amount) }}{% endif %}</td>
      <td></td>
    </tr>
    {% endfor %}
    <tr class="totals">
      <td colspan="2" class="right">WEEKLY TOTAL</td><td class="right">{{ "{:,.0f}".format(mz.bike) if mz.bike else "" }}</td><td></td>
      <td colspan="2" class="right">WEEKLY TOTAL</td><td class="right">{{ "{:,.0f}".format(mz.fork) if mz.fork else "" }}</td><td></td>
    </tr>
  </tbody>
</table>

{# ============================================================
   PAGE 4 — WAGES & LOANS REGISTER
   ============================================================ #}
<div class="page-break"></div>
<div class="title-bar">
  <div>VIMIT CONVERTERS LIMITED &nbsp;|&nbsp; <span class="sub">WEEKLY PETTY CASH &mdash; WAGES &amp; LOANS</span></div>
  <div class="sub">Wk {{ doc.week_no }} &middot; {{ doc.float }} Float &middot; {{ frappe.utils.format_date(doc.week_ending) if doc.week_ending else "" }}</div>
</div>

<div class="section-h">WAGES</div>
<table>
  <colgroup><col style="width:3%"><col style="width:9%"><col style="width:8%"><col style="width:22%"><col style="width:10%"><col style="width:24%"><col style="width:10%"><col style="width:10%"><col style="width:4%"></colgroup>
  <thead>
    <tr><th>#</th><th>DATE</th><th>TYPE</th><th>RECIPIENT</th><th>STAFF ID</th><th>REASON / REF</th><th>AMOUNT</th><th>SIGN</th><th>PAYE</th></tr>
  </thead>
  <tbody>
    {% for w in doc.wages_entries %}
    {% if w.recipient or w.amount or w.reason %}
    <tr>
      <td class="center">{{ w.row_idx }}</td>
      <td>{{ frappe.utils.format_date(w.txn_date) if w.txn_date else "" }}</td>
      <td class="center">{{ w.entry_type or "" }}</td>
      <td>{{ w.recipient or "" }}</td>
      <td>{{ w.staff_id or "" }}</td>
      <td>{{ w.reason or "" }}</td>
      <td class="right">{{ "{:,.0f}".format(w.amount) if w.amount else "" }}</td>
      <td></td>
      <td class="center">{% if w.paye %}Y{% endif %}</td>
    </tr>
    {% endif %}
    {% endfor %}
    <tr class="totals">
      <td colspan="6" class="right">WAGES TOTAL &rarr;</td>
      <td class="right hi">{{ "{:,.0f}".format(wl.wages) if wl.wages else "" }}</td>
      <td colspan="2"></td>
    </tr>
  </tbody>
</table>

<div class="section-h">STAFF LOANS ISSUED THIS WEEK</div>
<table>
  <colgroup><col style="width:3%"><col style="width:9%"><col style="width:22%"><col style="width:10%"><col style="width:26%"><col style="width:13%"><col style="width:13%"><col style="width:4%"></colgroup>
  <thead>
    <tr><th>#</th><th>DATE</th><th>RECIPIENT</th><th>STAFF ID</th><th>REASON / REF</th><th>ISSUED (KES)</th><th>SIGNED (KES)</th><th>PAYE</th></tr>
  </thead>
  <tbody>
    {% for l in doc.loan_entries %}
    {% if l.recipient or l.amount_issued or l.amount_signed or l.reason %}
    <tr>
      <td class="center">{{ l.row_idx }}</td>
      <td>{{ frappe.utils.format_date(l.txn_date) if l.txn_date else "" }}</td>
      <td>{{ l.recipient or "" }}</td>
      <td>{{ l.staff_id or "" }}</td>
      <td>{{ l.reason or "" }}</td>
      <td class="right">{{ "{:,.0f}".format(l.amount_issued) if l.amount_issued else "" }}</td>
      <td class="right">{{ "{:,.0f}".format(l.amount_signed) if l.amount_signed else "" }}</td>
      <td class="center">{% if l.paye %}Y{% endif %}</td>
    </tr>
    {% endif %}
    {% endfor %}
    <tr class="totals">
      <td colspan="5" class="right">LOANS ISSUED &rarr;</td>
      <td class="right hi">{{ "{:,.0f}".format(wl.loans) if wl.loans else "" }}</td>
      <td class="right hi">{{ "{:,.0f}".format(wl.signed) if wl.signed else "" }}</td>
      <td></td>
    </tr>
  </tbody>
</table>

<table style="margin-top:10px">
  <colgroup><col style="width:33%"><col style="width:33%"><col style="width:34%"></colgroup>
  <tr>
    <th>TOTAL WAGES PAID (KES)</th>
    <th>TOTAL LOANS ISSUED (KES)</th>
    <th>GRAND TOTAL CASH OUT (WAGES + LOANS)</th>
  </tr>
  <tr>
    <td class="right" style="height:30px">{{ "{:,.0f}".format(wl.wages) if wl.wages else "" }}</td>
    <td class="right">{{ "{:,.0f}".format(wl.loans) if wl.loans else "" }}</td>
    <td class="right hi">{{ "{:,.0f}".format(wl.wages + wl.loans) }}</td>
  </tr>
</table>

<p class="note">
  <span class="red">NOTE:</span>
  All wages and loans paid in cash are recorded here. The recipient signature on this sheet
  IS the supporting evidence &mdash; no petty cash voucher slip or ETR receipt is required for these entries.
  Tick PAYE for any payment requiring statutory deduction.
</p>

{# ============================================================
   PAGE 5 — LOAN LEDGER (full running list across all weeks/floats)
   Cross-sheet via frappe.get_all; falls back to this sheet's loans.
   ============================================================ #}
<div class="page-break"></div>
<div class="title-bar">
  <div>VIMIT CONVERTERS LIMITED &nbsp;|&nbsp; <span class="sub">PETTY CASH &mdash; LOAN LEDGER</span></div>
  <div class="sub">All loans as at {{ frappe.utils.format_date(doc.week_ending) if doc.week_ending else "" }} &middot; previous + this week</div>
</div>

{% if ledger.ok and ledger.rows %}
<div class="section-h">FULL LOAN LIST (all floats) &mdash; {{ ledger.rows | length }} loans</div>
<table>
  <colgroup><col style="width:4%"><col style="width:11%"><col style="width:9%"><col style="width:10%"><col style="width:19%"><col style="width:8%"><col style="width:16%"><col style="width:10%"><col style="width:10%"><col style="width:3%"></colgroup>
  <thead>
    <tr><th>#</th><th>WEEK ENDING</th><th>FLOAT</th><th>DATE</th><th>RECIPIENT</th><th>STAFF</th><th>REASON / REF</th><th>ISSUED</th><th>SIGNED-OFF</th><th>PAYE</th></tr>
  </thead>
  <tbody>
    {% for r in ledger.rows %}
    <tr {% if r.is_current %}style="background:#FFF8E1"{% endif %}>
      <td class="center">{{ loop.index }}</td>
      <td>{{ frappe.utils.format_date(r.week_ending) if r.week_ending else "" }}{% if r.is_current %} <strong>(new)</strong>{% endif %}</td>
      <td class="center">{{ r.float }}</td>
      <td>{{ frappe.utils.format_date(r.txn_date) if r.txn_date else "" }}</td>
      <td>{{ r.recipient or "" }}</td>
      <td class="center">{{ r.staff_id or "" }}</td>
      <td>{{ r.reason or "" }}</td>
      <td class="right">{{ "{:,.0f}".format(r.amount_issued) if r.amount_issued else "" }}</td>
      <td class="right">{{ "{:,.0f}".format(r.amount_signed) if r.amount_signed else "" }}</td>
      <td class="center">{% if r.paye %}Y{% endif %}</td>
    </tr>
    {% endfor %}
    <tr class="totals">
      <td colspan="7" class="right">RUNNING TOTAL &rarr;</td>
      <td class="right hi">{{ "{:,.0f}".format(ledger.issued) }}</td>
      <td class="right hi">{{ "{:,.0f}".format(ledger.signed) }}</td>
      <td></td>
    </tr>
  </tbody>
</table>
<p class="note">
  <span class="red">NOTE:</span>
  Running list of every loan issued up to and including this week, across all floats. Highlighted rows are
  this week&rsquo;s additions. <strong>Issued</strong> = cash paid out of the float; <strong>Signed-off</strong> =
  amount the recipient acknowledges owing.
</p>
{% else %}
<div class="section-h">THIS SHEET&rsquo;S LOANS (cross-sheet ledger unavailable)</div>
<table>
  <colgroup><col style="width:4%"><col style="width:12%"><col style="width:26%"><col style="width:10%"><col style="width:22%"><col style="width:12%"><col style="width:12%"><col style="width:4%"></colgroup>
  <thead>
    <tr><th>#</th><th>DATE</th><th>RECIPIENT</th><th>STAFF</th><th>REASON / REF</th><th>ISSUED</th><th>SIGNED-OFF</th><th>PAYE</th></tr>
  </thead>
  <tbody>
    {% for l in doc.loan_entries %}
    {% if l.recipient or l.amount_issued or l.amount_signed or l.reason %}
    <tr>
      <td class="center">{{ l.row_idx }}</td>
      <td>{{ frappe.utils.format_date(l.txn_date) if l.txn_date else "" }}</td>
      <td>{{ l.recipient or "" }}</td>
      <td class="center">{{ l.staff_id or "" }}</td>
      <td>{{ l.reason or "" }}</td>
      <td class="right">{{ "{:,.0f}".format(l.amount_issued) if l.amount_issued else "" }}</td>
      <td class="right">{{ "{:,.0f}".format(l.amount_signed) if l.amount_signed else "" }}</td>
      <td class="center">{% if l.paye %}Y{% endif %}</td>
    </tr>
    {% endif %}
    {% endfor %}
    <tr class="totals">
      <td colspan="5" class="right">TOTAL &rarr;</td>
      <td class="right hi">{{ "{:,.0f}".format(wl.loans) if wl.loans else "" }}</td>
      <td class="right hi">{{ "{:,.0f}".format(wl.signed) if wl.signed else "" }}</td>
      <td></td>
    </tr>
  </tbody>
</table>
<p class="note">
  <span class="red">NOTE:</span> Showing this sheet&rsquo;s loans only &mdash; the full cross-sheet running ledger
  could not be loaded in this render context.
</p>
{% endif %}

</div>
